using System;
using System.Reflection;
using System.Linq;

namespace ReflectTypes
{
    class Program
    {
        static void Main()
        {
            PrintTypes(typeof(Microsoft.Agents.AI.AgentLoop).Assembly, "Microsoft.Agents.AI 1.4.0");
            PrintTypes(typeof(Microsoft.Extensions.AI.IChatClient).Assembly, "Microsoft.Extensions.AI 10.5.0");
            PrintTypes(typeof(Microsoft.Extensions.AI.Abstractions.AIContent).Assembly, "Microsoft.Extensions.AI.Abstractions 10.5.0");
            PrintTypes(typeof(Microsoft.Extensions.AI.OpenAI.OpenAIChatClient).Assembly, "Microsoft.Extensions.AI.OpenAI 10.3.0");
        }

        static void PrintTypes(Assembly asm, string name)
        {
            Console.WriteLine($"\n{'='}{new string('=', name.Length + 2)}");
            Console.WriteLine($"= {name} =");
            Console.WriteLine($"{'='}{new string('=', name.Length + 2)}\n");

            var types = asm.GetTypes()
                .Where(t => t.IsPublic && !t.IsNested && (t.IsInterface || t.IsClass || t.IsEnum))
                .OrderBy(t => t.Namespace)
                .ThenBy(t => t.Name)
                .ToList();

            var namespaces = types.GroupBy(t => t.Namespace).OrderBy(g => g.Key);

            foreach (var ns in namespaces)
            {
                Console.WriteLine($"Namespace: {ns.Key}");
                foreach (var type in ns)
                {
                    string typeKind = type.IsInterface ? "interface" : type.IsEnum ? "enum" : "class";
                    string baseInfo = "";

                    if (type.IsInterface)
                    {
                        var inherited = type.GetInterfaces();
                        if (inherited.Length > 0)
                            baseInfo = $" : {string.Join(", ", inherited.Select(i => i.Name))}";
                    }
                    else if (!type.IsEnum && type.BaseType != typeof(object) && type.BaseType != null)
                    {
                        baseInfo = $" : {type.BaseType.Name}";
                    }

                    Console.WriteLine($"  [{typeKind}] {type.Name}{baseInfo}");

                    // Show key methods for important interfaces/classes
                    if ((type.Name.Contains("Agent") || type.Name.Contains("Chat") || 
                         type.Name.Contains("Tool") || type.Name.Contains("Function") ||
                         type.Name.Contains("Loop") || type.Name.Contains("Client") ||
                         type.Name.Contains("AI")) && (type.IsInterface || type.IsClass))
                    {
                        var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
                            .Where(m => !m.IsSpecialName && m.DeclaringType == type)
                            .Take(8)
                            .ToList();

                        if (methods.Count > 0)
                        {
                            foreach (var method in methods)
                            {
                                var returnType = method.ReturnType.Name;
                                var parms = string.Join(", ", method.GetParameters().Select(p => p.ParameterType.Name));
                                Console.WriteLine($"      {returnType} {method.Name}({parms})");
                            }
                            if (methods.Count == 8) Console.WriteLine($"      ... and more");
                        }
                    }
                }
                Console.WriteLine();
            }
        }
    }
}
