using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI (or compatible) API key.");
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var endpoint = Environment.GetEnvironmentVariable("OPENAI_ENDPOINT");

// --- Build IChatClient from OpenAI ---
var clientOptions = new OpenAIClientOptions();
if (endpoint is not null)
    clientOptions.Endpoint = new Uri(endpoint);

IChatClient chatClient = new OpenAIClient(apiKey, clientOptions)
    .GetChatClient(model)
    .AsIChatClient();

// --- Research tools ---
var notebook = new ResearchNotebook();
var webSearch = new WebSearchTool();

List<AITool> tools =
[
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
];

// --- Create the research agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to thoroughly research the topic
        the user provides.

        Follow this workflow:
        1. Break the topic into key aspects to investigate.
        2. Use SearchWeb to find information on each aspect (make several searches).
        3. Use AddNote to save important findings as you go.
        4. After gathering enough information, use GetNotes to review everything.
        5. Provide a comprehensive, well-structured summary of your findings.

        Be thorough but concise. Cite sources where possible.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and taking notes",
    tools: tools);

// --- Interactive loop ---
Console.WriteLine("╔═══════════════════════════════════════════╗");
Console.WriteLine("║         🔍  AI Research Agent             ║");
Console.WriteLine("╠═══════════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or 'quit'.   ║");
Console.WriteLine("╚═══════════════════════════════════════════╝");
Console.WriteLine();

var session = await agent.CreateSessionAsync();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic: ");
    Console.ResetColor();

    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(input) || input.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.ForegroundColor = ConsoleColor.Yellow;
    Console.WriteLine("\n🔬 Researching… (this may take a moment)\n");
    Console.ResetColor();

    notebook.Clear();

    try
    {
        var response = await agent.RunAsync(input, session);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("═══ Research Summary ═══");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();

        if (notebook.Notes.Count > 0)
        {
            Console.ForegroundColor = ConsoleColor.DarkGray;
            Console.WriteLine($"📝 {notebook.Notes.Count} note(s) taken during research");
            Console.ResetColor();
        }
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine();
}

Console.WriteLine("Goodbye!");

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------

/// <summary>Provides web search via the DuckDuckGo Instant-Answer API (no key required).</summary>
sealed class WebSearchTool
{
    private static readonly HttpClient s_http = new();

    [Description("Search the web for information on a query. Returns titles, snippets, and URLs.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            using var response = await s_http.GetAsync(url);
            response.EnsureSuccessStatusCode();
            var doc = await response.Content.ReadFromJsonAsync<JsonElement>();

            var results = new List<string>();

            // Abstract / summary
            var abstractText = doc.GetProperty("AbstractText").GetString();
            var abstractSource = doc.GetProperty("AbstractSource").GetString();
            var abstractUrl = doc.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
                results.Add($"**{abstractSource}**: {abstractText}\nURL: {abstractUrl}");

            // Related topics
            if (doc.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(8))
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        topic.TryGetProperty("FirstURL", out var topicUrl))
                    {
                        results.Add($"• {text.GetString()}\n  URL: {topicUrl.GetString()}");
                    }
                }
            }

            return results.Count > 0
                ? $"Search results for '{query}':\n\n{string.Join("\n\n", results)}"
                : $"No results found for '{query}'. Try a different query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }
}

/// <summary>In-memory notebook for collecting research notes.</summary>
sealed class ResearchNotebook
{
    public List<(string Title, string Content, DateTime Timestamp)> Notes { get; } = [];

    [Description("Save a research note for later reference.")]
    public string AddNote(
        [Description("Brief title for the note")] string title,
        [Description("The note content")] string content)
    {
        Notes.Add((title, content, DateTime.UtcNow));
        return $"Note #{Notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieve all research notes taken so far.")]
    public string GetNotes()
    {
        if (Notes.Count == 0)
            return "No notes taken yet.";

        return string.Join("\n\n", Notes.Select((n, i) =>
            $"--- Note #{i + 1}: {n.Title} ---\n{n.Content}"));
    }

    public void Clear() => Notes.Clear();
}

using System.ComponentModel;
using System.Net.Http.Json;
